package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithQuoteModeReturnsNewInstanceWithCorrectQuoteMode() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT;
        QuoteMode newQuoteMode = QuoteMode.ALL;

        CSVFormat modified = original.withQuoteMode(newQuoteMode);

        assertNotSame(original, modified, "withQuoteMode should return a new CSVFormat instance");
        assertEquals(newQuoteMode, modified.getQuoteMode(), "QuoteMode should be set to the new value");
        // All other fields should remain unchanged
        assertEquals(original.getDelimiter(), modified.getDelimiter(), "Delimiter should be unchanged");
        assertEquals(original.getQuoteCharacter(), modified.getQuoteCharacter(), "QuoteCharacter should be unchanged");
        assertEquals(original.getCommentMarker(), modified.getCommentMarker(), "CommentMarker should be unchanged");
        assertEquals(original.getEscapeCharacter(), modified.getEscapeCharacter(), "EscapeCharacter should be unchanged");
        assertEquals(original.getIgnoreSurroundingSpaces(), modified.getIgnoreSurroundingSpaces(), "IgnoreSurroundingSpaces should be unchanged");
        assertEquals(original.getIgnoreEmptyLines(), modified.getIgnoreEmptyLines(), "IgnoreEmptyLines should be unchanged");
        assertEquals(original.getRecordSeparator(), modified.getRecordSeparator(), "RecordSeparator should be unchanged");
        assertEquals(original.getNullString(), modified.getNullString(), "NullString should be unchanged");
        assertArrayEquals(original.getHeader(), modified.getHeader(), "Header should be unchanged");
        assertEquals(original.getSkipHeaderRecord(), modified.getSkipHeaderRecord(), "SkipHeaderRecord should be unchanged");
        assertEquals(original.getAllowMissingColumnNames(), modified.getAllowMissingColumnNames(), "AllowMissingColumnNames should be unchanged");

        // Test with null QuoteMode
        CSVFormat nullQuoteModeFormat = original.withQuoteMode(null);
        assertNull(nullQuoteModeFormat.getQuoteMode(), "QuoteMode should be null when set to null");
    }
}
